const e=JSON.parse('{"key":"v-25643f01","path":"/basics/MySQL/%E5%AE%9E%E8%B7%B5%E7%AF%87/10%E4%B8%BA%E4%BB%80%E4%B9%88%E6%9C%89%E6%97%B6%E4%BC%9A%E9%80%89%E9%94%99%E7%B4%A2%E5%BC%95.html","title":"为什么有时会选错索引","lang":"zh-CN","frontmatter":{"summary":"为什么有时会选错索引 前面我们介绍过索引，你已经知道了在 MySQL 中一张表其实是可以支持多个索引的。但是，你写 SQL 语句的时候，并没有主动指定使用哪个索引。也就是说，使用哪个索引是由 MySQL 来确定的。 不知道你有没有碰到过这种情况，一条本来可以执行得很快的语句，却由于 MySQL 选错了索引，而导致执行速度变得很慢？ 我们一起来看一个例子吧。 ","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-v2-demo.mrhope.site/basics/MySQL/%E5%AE%9E%E8%B7%B5%E7%AF%87/10%E4%B8%BA%E4%BB%80%E4%B9%88%E6%9C%89%E6%97%B6%E4%BC%9A%E9%80%89%E9%94%99%E7%B4%A2%E5%BC%95.html"}],["meta",{"property":"og:site_name","content":"Weiser"}],["meta",{"property":"og:title","content":"为什么有时会选错索引"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:updated_time","content":"2022-05-29T14:55:35.000Z"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:modified_time","content":"2022-05-29T14:55:35.000Z"}]]},"excerpt":"","headers":[{"level":2,"title":"优化器的逻辑","slug":"优化器的逻辑","link":"#优化器的逻辑","children":[]},{"level":2,"title":"索引选择异常和处理","slug":"索引选择异常和处理","link":"#索引选择异常和处理","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{"createdTime":1653836135000,"updatedTime":1653836135000,"contributors":[{"name":"xwzbupt","email":"xwze@bupt.cn","commits":1}]},"readingTime":{"minutes":15.78,"words":4735},"filePathRelative":"basics/MySQL/实践篇/10为什么有时会选错索引.md","localizedDate":"2022年5月29日"}');export{e as data};
